package com.google.gson;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

class JsonElementTest {

  @Test
  void testGetAsDouble_throwsUnsupportedOperationException() throws Exception {
    JsonElement jsonElement = new JsonElement() {
      @Override
      public JsonElement deepCopy() {
        return this;
      }
    };
    UnsupportedOperationException exception = assertThrows(UnsupportedOperationException.class, jsonElement::getAsDouble);
    assertEquals("JsonElement", exception.getMessage());
  }
}
